<?php
if(session_status()===PHP_SESSION_NONE)session_start();
if(empty($_SESSION['is_logged_in'])){header('Location: ../connexion.php');exit;}
if(!in_array($_SESSION['user_type']??'', ['admin','gestionnaire'],true)){header('Location: dashboard.php');exit;}
require_once __DIR__.'/../config/database.php';
function mh($v):string{return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
$menus=fetchAll('SELECT m.*,c.nom category_name FROM menus m JOIN categories c ON c.id=m.category_id WHERE m.supprimer=0 ORDER BY m.created_at DESC,m.id DESC');
$categories=fetchAll('SELECT id,nom FROM categories WHERE supprimer=0 ORDER BY nom');
$available=0;foreach($menus as $m)if($m->is_available)$available++;
$adminName=trim(($_SESSION['user_nom']??'Utilisateur').' '.($_SESSION['user_prenom']??''));$initials=strtoupper(substr($_SESSION['user_nom']??'U',0,1).substr($_SESSION['user_prenom']??'',0,1));
?>
<!doctype html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Gestion du menu — ISSALE</title>
<link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&family=Outfit:wght@600;700&display=swap" rel="stylesheet"><link href="https://cdn.jsdelivr.net/npm/bootstrap-icons@1.11.1/font/bootstrap-icons.css" rel="stylesheet">
<style>
:root{--primary:#8B1A1A;--dark:#5C0E0E;--gold:#D4A373;--bg:#FDF8F3;--surface:#fff;--sidebar:#1A120E;--text:#1A120E;--muted:#83766f;--border:#eadfd5;--green:#2d7d46;--red:#c0392b;--font:'Inter',sans-serif;--display:'Outfit',sans-serif}*{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--text);font-family:var(--font)}.sidebar{position:fixed;inset:0 auto 0 0;width:256px;padding:24px;background:var(--sidebar);display:flex;flex-direction:column;z-index:20}.brand{display:flex;gap:12px;align-items:center;margin-bottom:34px;color:#fff}.logo{width:42px;height:42px;border-radius:12px;background:linear-gradient(135deg,var(--primary),var(--dark));display:grid;place-items:center}.brand h1{font:700 18px var(--display);margin:0}.brand small{color:var(--gold)}nav{display:grid;gap:5px}.label{color:#887d78;font-size:10px;font-weight:700;letter-spacing:.12em;margin:16px 12px 6px}.nav{display:flex;align-items:center;gap:12px;padding:11px 13px;color:#bdb5b1;text-decoration:none;border-radius:11px;font-size:14px}.nav:hover{color:#fff;background:#ffffff12}.nav.active{background:var(--gold);color:#1A120E;font-weight:700}.user{margin-top:auto;padding-top:18px;border-top:1px solid #ffffff14;display:flex;gap:10px;align-items:center;color:#fff}.avatar{width:38px;height:38px;border-radius:11px;background:#ffffff12;color:var(--gold);display:grid;place-items:center;font-weight:700}.user p{margin:0;font-size:13px;font-weight:600}.user span{font-size:11px;color:#918783}.logout{margin-left:auto;color:#aaa}.main{margin-left:256px}.top{position:sticky;top:0;z-index:10;padding:17px 30px;background:#fdf8f3e8;backdrop-filter:blur(12px);border-bottom:1px solid var(--border);display:flex;justify-content:space-between;align-items:center}.top h2{font:700 23px var(--display);margin:0}.top small{color:var(--muted)}.menu-btn{display:none;border:0;background:none;font-size:24px}.content{padding:30px}.crumb{font-size:13px;color:var(--muted);margin-bottom:20px}.crumb a{color:var(--primary);text-decoration:none}.stats{display:grid;grid-template-columns:repeat(3,1fr);gap:15px;margin-bottom:22px}.stat{background:#fff;border:1px solid var(--border);border-radius:15px;padding:19px}.stat span{font-size:11px;text-transform:uppercase;color:var(--muted);font-weight:700}.stat strong{display:block;font:700 27px var(--display);margin-top:7px}.toolbar{display:flex;justify-content:space-between;gap:15px;margin-bottom:18px}.search{position:relative;max-width:380px;flex:1}.search i{position:absolute;left:14px;top:13px;color:#a39790}.search input,.filter{width:100%;padding:12px 14px 12px 40px;border:1px solid var(--border);border-radius:11px;background:#fff;font:14px var(--font);outline:none}.filter{padding-left:14px;width:auto}.tools{display:flex;gap:10px}.btn{border:0;border-radius:11px;padding:11px 17px;font:600 13px var(--font);cursor:pointer;display:inline-flex;align-items:center;gap:8px}.primary{background:var(--primary);color:#fff}.light{background:#f4ede7}.card{background:#fff;border:1px solid var(--border);border-radius:18px;overflow:hidden}.wrap{overflow:auto}table{width:100%;border-collapse:collapse}th{background:#fbf6f1;padding:13px 17px;text-align:left;text-transform:uppercase;letter-spacing:.06em;font-size:10px;color:#94867e}td{padding:14px 17px;border-top:1px solid var(--border);font-size:13px;color:var(--muted)}tr:hover td{background:#fdf9f5}.dish{display:flex;align-items:center;gap:11px}.dish-img{width:48px;height:48px;border-radius:11px;object-fit:cover;background:#f7e8e8;display:grid;place-items:center;color:var(--primary);font-size:20px}.dish strong{display:block;color:var(--text)}.dish small{display:block;max-width:260px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.badge{display:inline-block;padding:5px 9px;border-radius:99px;font-size:10px;font-weight:700}.on{background:#e8f5ec;color:var(--green)}.off{background:#fce8e8;color:var(--primary)}.category{background:#fff0df;color:#8a580d}.actions{display:flex;gap:6px}.icon{width:32px;height:32px;border:1px solid var(--border);border-radius:8px;background:#fff;cursor:pointer;color:#75675f}.icon:hover{color:var(--primary);border-color:var(--primary)}.empty{text-align:center;padding:55px}.overlay{position:fixed;inset:0;background:#1a120e88;display:none;align-items:center;justify-content:center;padding:20px;z-index:100}.overlay.open{display:flex}.modal{width:min(680px,100%);max-height:92vh;overflow:auto;background:#fff;border-radius:20px;box-shadow:0 24px 70px #0004}.head{display:flex;justify-content:space-between;padding:22px 24px;border-bottom:1px solid var(--border)}.head h3{font:700 19px var(--display);margin:0}.close{border:0;background:none;font-size:23px}.body{padding:24px}.grid{display:grid;grid-template-columns:1fr 1fr;gap:16px}.field label{display:block;font-size:12px;font-weight:700;margin-bottom:7px}.field input,.field select,.field textarea{width:100%;padding:11px;border:1px solid var(--border);border-radius:10px;font:14px var(--font)}.full{grid-column:1/-1}.switch{display:flex;align-items:center;gap:9px}.foot{display:flex;justify-content:flex-end;gap:9px;padding:18px 24px;border-top:1px solid var(--border)}.toast{position:fixed;right:22px;bottom:22px;background:#1A120E;color:#fff;padding:14px 18px;border-radius:11px;z-index:200}.mobile-overlay{display:none}@media(max-width:768px){.sidebar{transform:translateX(-100%);transition:.2s}.sidebar.open{transform:none}.mobile-overlay.open{display:block;position:fixed;inset:0;background:#0006;z-index:15}.main{margin-left:0}.menu-btn{display:block}.content{padding:20px 16px}.stats{grid-template-columns:1fr}.toolbar{flex-direction:column}.tools{flex-wrap:wrap}.grid{grid-template-columns:1fr}.full{grid-column:auto}}
</style></head><body>
<aside class="sidebar" id="sidebar"><div class="brand"><div class="logo"><i class="bi bi-cup-hot-fill"></i></div><div><h1>ISSALE</h1><small>Administration</small></div></div><nav><div class="label">Menu</div><a class="nav" href="dashboard.php"><i class="bi bi-grid-1x2"></i>Tableau de bord</a><a class="nav active" href="menus.php"><i class="bi bi-journal-richtext"></i>Menus</a><a class="nav" href="categories.php"><i class="bi bi-tags"></i>Catégories</a><?php if(($_SESSION['user_type']??'')==='admin'):?><a class="nav" href="utilisateurs.php"><i class="bi bi-people"></i>Utilisateurs</a><?php endif;?><a class="nav" href="settings.php"><i class="bi bi-gear"></i>Paramètres</a></nav><div class="user"><div class="avatar"><?=mh($initials)?></div><div><p><?=mh($adminName)?></p><span><?=mh(ucfirst($_SESSION['user_type']??''))?></span></div><a class="logout" href="../models/logout.php"><i class="bi bi-box-arrow-right"></i></a></div></aside><div class="mobile-overlay" id="mobileOverlay" onclick="toggleSidebar()"></div>
<main class="main"><header class="top"><div style="display:flex;align-items:center;gap:12px"><button class="menu-btn" onclick="toggleSidebar()"><i class="bi bi-list"></i></button><div><h2>Gestion du menu</h2><small>Plats, prix et disponibilités</small></div></div><span class="badge category">Restaurant ISSALE</span></header><section class="content"><div class="crumb"><a href="dashboard.php">Tableau de bord</a> &nbsp;/&nbsp; Menus</div>
<div class="stats"><div class="stat"><span>Plats enregistrés</span><strong><?=count($menus)?></strong></div><div class="stat"><span>Disponibles</span><strong><?=$available?></strong></div><div class="stat"><span>Catégories</span><strong><?=count($categories)?></strong></div></div>
<div class="toolbar"><div class="search"><i class="bi bi-search"></i><input id="search" oninput="filterMenus()" placeholder="Rechercher un plat…"></div><div class="tools"><select class="filter" id="categoryFilter" onchange="filterMenus()"><option value="">Toutes les catégories</option><?php foreach($categories as $c):?><option value="<?=$c->id?>"><?=mh($c->nom)?></option><?php endforeach;?></select><button class="btn primary" onclick="openMenu()"><i class="bi bi-plus-lg"></i>Ajouter un plat</button></div></div>
<div class="card"><div class="wrap"><table><thead><tr><th>Plat</th><th>Catégorie</th><th>Prix</th><th>Préparation</th><th>Statut</th><th>Actions</th></tr></thead><tbody id="rows"><?php if(!$menus):?><tr><td colspan="6" class="empty">Aucun plat enregistré.</td></tr><?php endif;?><?php foreach($menus as $m):?><tr id="menu-<?=$m->id?>" data-category="<?=$m->category_id?>" data-search="<?=mh(strtolower($m->nom.' '.$m->category_name.' '.$m->description))?>"><td><div class="dish"><?php if($m->image):?><img class="dish-img" src="../<?=mh($m->image)?>" alt=""><?php else:?><span class="dish-img"><i class="bi bi-egg-fried"></i></span><?php endif;?><div><strong><?=mh($m->nom)?></strong><small><?=mh($m->description?:'Aucune description')?></small></div></div></td><td><span class="badge category"><?=mh($m->category_name)?></span></td><td><strong style="color:var(--primary)"><?=number_format((float)$m->price,0,',',' ')?> FC</strong></td><td><?=$m->preparation_time?> min</td><td><span class="badge <?=$m->is_available?'on':'off'?>"><?=$m->is_available?'Disponible':'Indisponible'?></span></td><td><div class="actions"><button class="icon" onclick='editMenu(<?=json_encode($m,JSON_HEX_APOS|JSON_HEX_QUOT)?>)'><i class="bi bi-pencil"></i></button><button class="icon" onclick="deleteMenu(<?=$m->id?>,<?=mh(json_encode($m->nom))?>)"><i class="bi bi-trash"></i></button></div></td></tr><?php endforeach;?></tbody></table></div></div></section></main>
<div class="overlay" id="menuModal"><form class="modal" id="menuForm" onsubmit="saveMenu(event)" enctype="multipart/form-data"><div class="head"><h3 id="modalTitle">Ajouter un plat</h3><button type="button" class="close" onclick="closeMenu()">×</button></div><div class="body"><input type="hidden" name="action" id="action" value="create"><input type="hidden" name="id" id="menuId"><input type="hidden" name="current_image" id="currentImage"><div class="grid"><div class="field"><label>Nom du plat *</label><input name="nom" id="nom" required></div><div class="field"><label>Catégorie *</label><select name="category_id" id="categoryId" required><option value="">Sélectionner…</option><?php foreach($categories as $c):?><option value="<?=$c->id?>"><?=mh($c->nom)?></option><?php endforeach;?></select></div><div class="field"><label>Prix (FC) *</label><input type="number" min="0" step="1" name="price" id="price" required></div><div class="field"><label>Temps de préparation</label><input type="number" min="1" name="preparation_time" id="prep" value="15"></div><div class="field full"><label>Description</label><textarea name="description" id="description" rows="3"></textarea></div><div class="field full"><label>Image</label><input type="file" name="image" accept="image/jpeg,image/png,image/webp"></div><div class="field full switch"><input style="width:auto" type="checkbox" name="is_available" id="available" value="1" checked><label style="margin:0">Disponible sur le menu client</label></div></div></div><div class="foot"><button type="button" class="btn light" onclick="closeMenu()">Annuler</button><button class="btn primary" id="saveBtn">Enregistrer</button></div></form></div>
<div class="overlay" id="deleteModal"><div class="modal" style="max-width:430px"><div class="head"><h3>Confirmer la suppression</h3><button type="button" class="close" onclick="closeDeleteModal()">×</button></div><div class="body" style="text-align:center"><div style="width:58px;height:58px;border-radius:50%;display:grid;place-items:center;margin:0 auto 16px;background:#fce8e8;color:var(--red);font-size:25px"><i class="bi bi-exclamation-triangle"></i></div><p>Voulez-vous vraiment supprimer le plat</p><strong id="deleteMenuName" style="color:var(--primary)"></strong><p style="font-size:12px;color:var(--muted);margin-top:12px">Cette action retirera le plat du menu.</p></div><div class="foot"><button type="button" class="btn light" onclick="closeDeleteModal()">Annuler</button><button type="button" class="btn" id="confirmDeleteBtn" style="background:var(--red);color:#fff" onclick="executeDeleteMenu()"><i class="bi bi-trash"></i>Supprimer</button></div></div></div>
<script>
const modal=document.getElementById('menuModal'),form=document.getElementById('menuForm');function toggleSidebar(){sidebar.classList.toggle('open');mobileOverlay.classList.toggle('open')}function openMenu(){form.reset();action.value='create';menuId.value='';currentImage.value='';available.checked=true;modalTitle.textContent='Ajouter un plat';modal.classList.add('open')}function editMenu(m){form.reset();action.value='update';menuId.value=m.id;currentImage.value=m.image||'';nom.value=m.nom;categoryId.value=m.category_id;price.value=m.price;prep.value=m.preparation_time;description.value=m.description||'';available.checked=Number(m.is_available)===1;modalTitle.textContent='Modifier le plat';modal.classList.add('open')}function closeMenu(){modal.classList.remove('open')}
async function saveMenu(e){e.preventDefault();saveBtn.disabled=true;try{const r=await fetch('../models/traitement/menus-post.php',{method:'POST',body:new FormData(form)}),o=await r.json();toast(o.message);if(o.success)setTimeout(()=>location.reload(),600)}catch(e){toast('Une erreur est survenue.')}finally{saveBtn.disabled=false}}
let menuToDelete=null;function deleteMenu(id,name){menuToDelete=id;deleteMenuName.textContent=name;deleteModal.classList.add('open')}function closeDeleteModal(){deleteModal.classList.remove('open');menuToDelete=null}async function executeDeleteMenu(){if(!menuToDelete)return;confirmDeleteBtn.disabled=true;const id=menuToDelete;try{const r=await fetch('../models/traitement/menus-post.php',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({action:'delete',id})}),o=await r.json();toast(o.message);if(o.success){document.getElementById('menu-'+id)?.remove();closeDeleteModal()}}catch(e){toast('Une erreur est survenue.')}finally{confirmDeleteBtn.disabled=false}}
function filterMenus(){const q=search.value.toLowerCase(),c=categoryFilter.value;document.querySelectorAll('#rows tr[data-search]').forEach(r=>r.style.display=(!q||r.dataset.search.includes(q))&&(!c||r.dataset.category===c)?'':'none')}function toast(msg){document.querySelector('.toast')?.remove();const t=document.createElement('div');t.className='toast';t.textContent=msg;document.body.append(t);setTimeout(()=>t.remove(),3500)}modal.onclick=e=>{if(e.target===modal)closeMenu()};
deleteModal.onclick=e=>{if(e.target===deleteModal)closeDeleteModal()};document.addEventListener('keydown',e=>{if(e.key==='Escape'){closeMenu();closeDeleteModal()}});
</script><script src="../assets/js/sidebar-sync.js"></script></body></html>
